import React, { useState } from 'react';
import axios from 'axios';

const API = axios.create({ baseURL: 'http://localhost:8000' });

function Sidebar({
    loggedIn,
    username,
    setLoggedIn,
    setUsername,
    onClearHistory,
    onFetchMistakes,
    onFetchReport,
    onDownloadWorksheet,
    sidebarOpen,
    setSidebarOpen,
    currentTheme,
    setCurrentTheme,
    theme,
}) {
    const [loginUser, setLoginUser] = useState('');
    const [loginPass, setLoginPass] = useState('');
    const [regUser, setRegUser] = useState('');
    const [regPass, setRegPass] = useState('');
    const [msg, setMsg] = useState('');
    const [showClearConfirm, setShowClearConfirm] = useState(false);
    const [showLogoutConfirm, setShowLogoutConfirm] = useState(false);

    const handleLogin = async () => {
        try {
            const res = await API.post('/api/login', {
                username: loginUser,
                password: loginPass,
            });
            setMsg(res.data.message);
            if (res.data.success) {
                setLoggedIn(true);
                setUsername(loginUser);
            }
        } catch (err) {
            setMsg('网络错误');
        }
    };

    const handleRegister = async () => {
        try {
            const res = await API.post('/api/register', {
                username: regUser,
                password: regPass,
            });
            setMsg(res.data.message);
            if (res.data.success) {
                setLoggedIn(true);
                setUsername(regUser);
            }
        } catch (err) {
            setMsg('网络错误');
        }
    };

    const handleLogout = () => {
        setLoggedIn(false);
        setUsername('游客');
        setShowLogoutConfirm(false);
    };

    const themeKeys = ['pink', 'blue', 'brown'];

    // 折叠状态
    if (!sidebarOpen) {
        return (
            <div className="w-14 bg-white/60 backdrop-blur-xl border-r border-gray-200 flex flex-col items-center py-4 gap-4">
                <button
                    onClick={() => setSidebarOpen(true)}
                    className="text-xl hover:scale-110 transition"
                    title="展开工具栏"
                >
                    📂
                </button>
            </div>
        );
    }

    return (
        <div className="w-72 bg-white/60 backdrop-blur-xl shadow-xl border-r border-gray-100 flex flex-col gap-4 p-4 overflow-y-auto transition-all duration-300">
            {/* 折叠按钮 */}
            <div className="flex justify-between items-center">
                <h2 className="text-xl font-bold text-purple-600">🧰 神奇工具箱</h2>
                <button onClick={() => setSidebarOpen(false)} className="text-gray-400 hover:text-gray-600">
                    ◀
                </button>
            </div>

            {/* 学习工具 */}
            <div className="space-y-2">
                <div className="text-xs text-gray-400 font-semibold uppercase tracking-wider">📚 学习工具</div>
                <button onClick={onFetchMistakes} className={`${theme.sidebarBtn} w-full py-2 px-4 rounded-xl text-sm font-semibold transition`}>
                    📖 错题本 <span className="text-xs opacity-70 ml-1">整理薄弱点</span>
                </button>
                <button onClick={onFetchReport} className={`${theme.sidebarBtn} w-full py-2 px-4 rounded-xl text-sm font-semibold transition`}>
                    📊 学习周报 <span className="text-xs opacity-70 ml-1">进步看得见</span>
                </button>
            </div>

            {/* 作业与数据 */}
            <div className="space-y-2">
                <div className="text-xs text-gray-400 font-semibold uppercase tracking-wider">📝 作业与数据</div>
                <button onClick={() => { }} className={`${theme.sidebarBtn} w-full py-2 px-4 rounded-xl text-sm font-semibold transition`}>
                    ✏️ 批改作业 <span className="text-xs opacity-70 ml-1">拍照或粘贴</span>
                </button>
                <div className="flex gap-2">
                    <button onClick={() => onDownloadWorksheet(false)} className={`${theme.sidebarBtn} flex-1 py-2 text-sm`}>📥 无答案</button>
                    <button onClick={() => onDownloadWorksheet(true)} className={`${theme.sidebarBtn} flex-1 py-2 text-sm`}>📥 含答案</button>
                </div>
                <button onClick={() => setShowClearConfirm(true)} className={`${theme.sidebarBtn} w-full py-2 px-4 rounded-xl text-sm font-semibold transition`}>
                    🗑️ 清空对话 <span className="text-xs opacity-70 ml-1">谨慎哦</span>
                </button>
                {showClearConfirm && (
                    <div className="bg-white p-2 rounded-lg text-xs text-gray-600 flex gap-2">
                        <span>确定清空？</span>
                        <button onClick={() => { onClearHistory(); setShowClearConfirm(false); }} className="text-red-500 font-bold">确定</button>
                        <button onClick={() => setShowClearConfirm(false)} className="text-gray-400">取消</button>
                    </div>
                )}
            </div>

            {/* 账号管理 */}
            <div className="space-y-2">
                <div className="text-xs text-gray-400 font-semibold uppercase tracking-wider">👤 账号管理</div>
                {loggedIn ? (
                    <div className="flex flex-col gap-2">
                        <div className="text-sm font-medium">👤 {username}</div>
                        <button onClick={() => setShowLogoutConfirm(true)} className={`${theme.sidebarBtn} py-2 text-sm`}>🚪 退出登录</button>
                        {showLogoutConfirm && (
                            <div className="bg-white p-2 rounded-lg text-xs text-gray-600 flex gap-2">
                                <span>确定退出？</span>
                                <button onClick={handleLogout} className="text-red-500 font-bold">确定</button>
                                <button onClick={() => setShowLogoutConfirm(false)} className="text-gray-400">取消</button>
                            </div>
                        )}
                    </div>
                ) : (
                    <div className="space-y-3">
                        <input
                            type="text"
                            placeholder="用户名"
                            value={loginUser}
                            onChange={e => setLoginUser(e.target.value)}
                            className="w-full px-3 py-2 border border-purple-200 rounded-lg text-sm bg-white/70"
                        />
                        <input
                            type="password"
                            placeholder="密码"
                            value={loginPass}
                            onChange={e => setLoginPass(e.target.value)}
                            className="w-full px-3 py-2 border border-purple-200 rounded-lg text-sm bg-white/70"
                        />
                        <button onClick={handleLogin} className={`${theme.sidebarBtn} w-full py-2 text-sm`}>🔑 登录</button>
                        <button onClick={handleRegister} className={`${theme.sidebarBtn} w-full py-2 text-sm`}>📝 注册</button>
                        {msg && <p className="text-xs text-gray-500">{msg}</p>}
                    </div>
                )}
            </div>

            {/* 主题切换 */}
            <div className="mt-auto pt-2 border-t border-gray-200">
                <div className="text-xs text-gray-400 font-semibold uppercase tracking-wider mb-2">🎨 主题切换</div>
                <div className="flex gap-2">
                    {themeKeys.map(key => (
                        <button
                            key={key}
                            onClick={() => setCurrentTheme(key)}
                            className={`w-6 h-6 rounded-full bg-gradient-to-br ${key === 'pink' ? 'from-pink-300 to-purple-300' :
                                key === 'blue' ? 'from-blue-300 to-cyan-300' :
                                    'from-amber-300 to-orange-300'
                                } ${currentTheme === key ? 'ring-2 ring-purple-500' : ''}`}
                            title={key === 'pink' ? '柔雾粉紫' : key === 'blue' ? '晴空青蓝' : '松露暖棕'}
                        />
                    ))}
                </div>
            </div>
        </div>
    );
}

export default Sidebar;
